def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triple objects about universities (or related entities)
    into a single fluent sentence with proper grammatical structure.
    """
    if not triples:
        return ""

    # Helper function to strip quotes from object values
    def clean_object(obj):
        if obj and len(obj) >= 2 and ((obj.startswith('"') and obj.endswith('"')) or (obj.startswith("'") and obj.endswith("'"))):
            return obj[1:-1]
        return obj

    # Mapping from predicate to a readable phrase template.
    templates = {
        "city": "{subject} is located in {object}",
        "country": "{subject} is in {object}",
        "latinName": "{subject}'s Latin name is {object}",
        "nickname": "{subject}'s nickname is {object}",
        "rector": "{subject}'s rector is {object}",
        "academicStaffSize": "{subject} has an academic staff of {object}",
        "established": "{subject} was established in {object}",
        "state": "{subject} is in the state of {object}",
        "governmentType": "{subject} has a government type of {object}",
        "hasToItsNortheast": "{subject} has to its northeast {object}",
        "dean": "{subject}'s dean is {object}",
        "location": "{subject} is located in {object}",
        "numberOfStudents": "{subject} has {object} students",
        "affiliation": "{subject} is affiliated with {object}",
        "director": "{subject}'s director is {object}",
        "motto": "{subject}'s motto is \"{object}\"",
        "numberOfPostgraduateStudents": "{subject} has {object} postgraduate students",
        "numberOfUndergraduateStudents": "{subject} has {object} undergraduate students",
        "officialSchoolColour": "{subject}'s official school colour is {object}",
        "outlookRanking": "{subject} is ranked {object} in the Outlook ranking",
        "sportsOffered": "{subject} offers the sport {object}",
        "wasGivenTheTechnicalCampusStatusBy": "{subject} was given the technical campus status by {object}",
        "founder": "{subject} was founded by {object}",
        "leader": "{subject} is led by {object}",
        "leaderTitle": "{subject}'s leader title is {object}",
        "religion": "{subject}'s religion is {object}",
        "headquarter": "{subject}'s headquarter is {object}",
        "largestCity": "{subject}'s largest city is {object}",
        "river": "{subject}'s river is {object}",
        "hasToItsWest": "{subject} has to its west {object}",
        "anthem": "{subject}'s anthem is \"{object}\"",
        "ethnicGroup": "{subject}'s ethnic group includes {object}",
        "legislature": "{subject}'s legislature is {object}",
        "sportGoverningBody": "{subject}'s sport governing body is {object}",
        "isPartOf": "{subject} is part of {object}",
        "neighboringMunicipality": "{subject} neighbors {object}",
        "capital": "{subject}'s capital is {object}",
        "patronSaint": "{subject}'s patron saint is {object}",
        "hasToItsNorthwest": "{subject} has to its northwest {object}",
        "campus": "{subject}'s campus is located at {object}",
        "president": "{subject}'s president is {object}",
        "staff": "{subject} has {object} staff members",
        "numberOfDoctoralStudents": "{subject} has {object} doctoral students",
        "elevationAboveTheSeaLevel": "{subject} is at an elevation of {object} meters above sea level",
        "postalCode": "{subject}'s postal code is {object}",
        "longName": "{subject}'s long name is {object}",
    }

    # Group triples by subject
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the main subject (prefer university-related subjects)
    main_subject = None
    for subj in subject_triples.keys():
        if "University" in subj or "College" in subj or "Institute" in subj:
            main_subject = subj
            break
    if not main_subject and subject_triples:
        main_subject = list(subject_triples.keys())[0]

    # Build main sentence from main subject triples without repeating subject name
    main_clauses = []
    related_entities = {}  # Maps entity -> list of triples about that entity
    # Track country/city entities for including their information
    country_entity = None
    city_entity = None

    # Track which objects from main subject are other entities
    referenced_entities = set()

    # First pass: collect all information by entity
    entity_triples = {}
    for t in triples:
        # Clean object values to remove unnecessary quotes
        t_clean = Triple(t.subject, t.predicate, clean_object(t.object))
        if t_clean.subject not in entity_triples:
            entity_triples[t_clean.subject] = []
        entity_triples[t_clean.subject].append(t_clean)
    triples = [Triple(t.subject, t.predicate, clean_object(t.object)) for t in triples]

    # Build clauses for main subject, avoiding subject repetition
    for t in triples:
        if t.subject == main_subject:
            if t.predicate in ["city", "country", "state", "location", "isPartOf"]:
                clause = f"located in {t.object}"
            elif t.predicate == "established":
                clause = f"established in {t.object}"
            elif t.predicate == "affiliation":
                clause = f"affiliated with {t.object}"
            elif t.predicate in ["president", "director", "rector", "dean"]:
                clause = f"{t.predicate} {t.object}"
            elif t.predicate == "numberOfStudents":
                clause = f"has {t.object} students"
            elif t.predicate == "staff":
                clause = f"has {t.object} staff"
            elif t.predicate == "academicStaffSize":
                clause = f"has {t.object} academic staff"
            elif t.predicate == "numberOfPostgraduateStudents":
                clause = f"has {t.object} postgraduate students"
            elif t.predicate == "numberOfUndergraduateStudents":
                clause = f"has {t.object} undergraduate students"
            elif t.predicate == "numberOfDoctoralStudents":
                clause = f"has {t.object} doctoral students"
            elif t.predicate == "outlookRanking":
                clause = f"ranked {t.object}"
            elif t.predicate == "sportsOffered":
                clause = f"offers {t.object}"
            elif t.predicate == "motto":
                clause = f"with motto \"{t.object}\""
            elif t.predicate == "nickname":
                clause = f"known as {t.object}"
            elif t.predicate == "latinName":
                clause = f"Latin name {t.object}"
            elif t.predicate == "officialSchoolColour":
                clause = f"colours {t.object}"
            elif t.predicate == "campus":
                clause = f"campus at {t.object}"
            elif t.predicate == "wasGivenTheTechnicalCampusStatusBy":
                clause = f"technical campus status by {t.object}"
            elif t.predicate == "leader":
                clause = f"led by {t.object}"
            elif t.predicate == "leaderTitle":
                clause = f"leader title {t.object}"
            elif t.predicate == "religion":
                clause = f"religion {t.object}"
            elif t.predicate == "capital":
                clause = f"capital {t.object}"
            elif t.predicate == "headquarter":
                clause = f"headquartered in {t.object}"
            elif t.predicate == "largestCity":
                clause = f"largest city {t.object}"
            elif t.predicate == "river":
                clause = f"river {t.object}"
            elif t.predicate == "ethnicGroup":
                clause = f"ethnic group {t.object}"
            elif t.predicate == "legislature":
                clause = f"legislature {t.object}"
            elif t.predicate == "anthem":
                clause = f"anthem \"{t.object}\""
            elif t.predicate == "patronSaint":
                clause = f"patron saint {t.object}"
            elif t.predicate == "elevationAboveTheSeaLevel":
                clause = f"elevation {t.object} meters"
            elif t.predicate == "postalCode":
                clause = f"postal code {t.object}"
            elif t.predicate == "longName":
                clause = f"long name {t.object}"
            elif t.predicate == "founder":
                clause = f"founded by {t.object}"
            elif t.predicate == "neighboringMunicipality":
                clause = f"neighbors {t.object}"
            elif t.predicate == "hasToItsNortheast":
                clause = f"northeast {t.object}"
            elif t.predicate == "hasToItsWest":
                clause = f"west {t.object}"
            elif t.predicate == "hasToItsNorthwest":
                clause = f"northwest {t.object}"
            elif t.predicate == "governmentType":
                clause = f"government type {t.object}"
            elif t.predicate == "sportGoverningBody":
                clause = f"sport governing body {t.object}"
            else:
                clause = f"{t.predicate} {t.object}"
            main_clauses.append(clause)
            referenced_entities.add(t.object)
        else:
            # Track related entities for potential relative clauses
            if t.object not in related_entities:
                related_entities[t.object] = []
            related_entities[t.object].append(t)

    # Build main sentence from all main subject clauses
    if main_clauses:
        # Combine main clauses with proper conjunctions - remove subject repetition
        if len(main_clauses) == 1:
            sentence = main_clauses[0]
        else:
            # Combine first clause with others using commas and 'and'
            first = main_clauses[0]
            rest = main_clauses[1:]
            if rest:
                last = rest[-1]
                middle = ", ".join(rest[:-1])
                if middle:
                    sentence = f"{first}, {middle}, and {last}"
                else:
                    sentence = f"{first} and {last}"
            else:
                sentence = first
        # Prepend subject name once
        sentence = f"{main_subject} {sentence}"
    else:
        # Fallback to first triple if no main subject found
        if triples:
            tmpl = templates.get(triples[0].predicate, "{subject} {predicate} {object}")
            sentence = tmpl.format(
                subject=triples[0].subject,
                predicate=triples[0].predicate,
                object=triples[0].object
            )
        else:
            sentence = ""

    # Add relative clauses for related entities with their information
    relative_clauses = []
    for entity, entity_triples_list in related_entities.items():
        if entity == main_subject:
            continue
        # Build relative clause for this related entity (include ALL its triples)
        rel_clauses = []
        for t in entity_triples_list:
            if t.subject == entity:
                tmpl = templates.get(t.predicate, "{subject} {predicate} {object}")
                rel_clauses.append(tmpl.format(subject=t.subject, predicate=t.predicate, object=t.object))
        if rel_clauses:
            if len(rel_clauses) == 1:
                relative_clauses.append(f"which {rel_clauses[0]}")
            else:
                combined = ", ".join(rel_clauses[:-1]) + (f", and {rel_clauses[-1]}" if len(rel_clauses) > 1 else "")
                relative_clauses.append(f"which {combined}")

    # Combine main sentence with relative clauses
    if relative_clauses:
        sentence = sentence + ", " + ", ".join(relative_clauses)

    # Ensure the sentence ends with a period and starts with a capital letter
    if sentence:
        sentence = sentence.rstrip()
        if not sentence.endswith('.'):
            sentence = sentence + "."
        sentence = sentence[0].upper() + sentence[1:]

    return sentence

